### Response:
```cpp
#include<bits/stdc++.h>
const int MAXN=1e5+5;
int n,cnt,flag;
int ans[MAXN],tot;
char map[1005][1005];
int main(){
 freopen("zip.in","r",stdin);
  freopen("zip.out","w",stdout);
  scanf("%s",map[1]+1);
  n=strlen(map[1]+1);
  for(int i=2;i<=n;++i){
    scanf("%s",map[i]+1);
  }
  flag=0;
  for(int i=1;i<=n;++i){
    for(int j=1;j<=n;++j){
      if(map[i][j]-'0'==flag)++cnt;
      else{
        ans[++tot]=cnt;
        flag^=1;
        cnt=1;
      }
    }
  }
  ans[++tot]=cnt;
  printf("%d ",n);
  for(int i=1;i<=tot;++i){
    printf("%d ",ans[i]);
  }return 0;
}
```

