```cpp
#include<bits/stdc++.h>
using namespace std;
int n,m;
struct s{
    int no,mxh,s;
};
struct q{
    int h;
};
bool cmps(s a,s b)
{
    return a.mxh<b.mxh;
}
bool cmpq(q a,q b)
{
    return a.h<b.h;
}
