Problem Description:
# p Nodes
Given a directed tree with a total of $n$ nodes, if a node's degree is not less than the degrees of all its children and its parent (if there is a parent or child), then we call this node a $p$ node. Now you are given a tree and you need to count the number of $p$ nodes.

### Input format

The first line of the input contains an integer $t$ ($1\le t\le 100$), indicating the number of test cases.

For the next $t$ groups of data, the first line of each group contains a number $n$ ($1\le n\le 1000$), indicating the number of nodes in the tree.

Then $n-1$ lines, each line containing two numbers $x$ and $y$ ($0\lt x,y\lt n$), representing that $y$ is the child node of $x$, separated by a space.

### Output format

Output $t$ lines, each line with an integer, representing the number of $p$ nodes.

Your program should use file input and output. Read the input from a file named 'p.in' and write the output to a file named 'p.out'.

### Time Limit
1000ms

### Memory Limit
131072KB

This is an incorrect code to the problem:
```c++
#include<bits/stdc++.h>
using namespace std;
int main()
{
    freopen("p.in","r",stdin);
    freopen("p.out","w",stdout);
    int t,n,x,y,p,o;
    cin>>t;
    for(int j=1;j<=t;j++)
    {
        p=0;
        cin>>n;
        vector<int> G[n+1];
        for(int i=2;i<=n;i++)
        {
            cin>>x>>y;
            G[x].push_back(y);
            G[y].push_back(x);
        }
        for(int i=0;i<n;i++)
        {
            o=0;
            for(int v=0;v<G[i].size();v++)
            {
                if(G[i].size()<G[G[i][v]].size())
                {
                    o++;
                }
            }
            if(o==0)
            {
                p++;
            }
        }
        cout<<p<<endl;
    }

}
```
### Response:
```cpp
#include<bits/stdc++.h>
using namespace std;
int main()
{
    freopen("p.in","r",stdin);
    freopen("p.out","w",stdout);
    int t,n,x,y,p,o;
    cin>>t;
    int degree[t+1][100000];
    for(int j=1;j<=t;j++)
    {
        p=0;
        cin>>n;
        vector<int> G[n+1];
        for(int i=0;i<=n;i++)
        {
            degree[j][i]=0;
        }
        for(int i=2;i<=n;i++)
        {
            cin>>x>>y;
            G[x].push_back(y);
            G[y].push_back(x);
            degree[j][x]++;
        }
        for(int i=1;i<=n;i++)
        {
            o=0;
            for(int v=0;v<G[i].size();v++)
            {
                if(degree[j][i]<degree[j][G[i][v]])
                {
                    o++;
                    break;
                }
            }
            if(o==0)
            {
                p++;
            }
        }
        cout<<p<<endl;
    }

}
```

