	int x, y, z;
    char s;
    cin >> x >> y >> z;
	int i = 0;
	while (x--) {
        cin >> s;
        if (s >= 'A' && s <= 'Z') {
            s = (s - 'A' + x) % 26 + 'A';
        }else if(s >= 'a' && s <= 'z') {
            s = (s - 'a' + x) % 26 + 'a';
        }else if (s >= '0' && s <= '9') {
            s = (s - '0' + x) % 10 + '0';
        }else if ((i+1)%y==0) {
        }
        cout << ;
	}
	return 0;
}
```
