# Binary Tree Sorting
Given a binary tree of size $N$ with its postorder and inorder traversals, please restore the original binary tree. Here, it is assumed that the node numbers $i$ are distinct positive integers and less than $1000$.

### Input Format

The first line of the input gives a positive integer $N(N\le30)$, which is the number of nodes in the binary tree. The second line gives its postorder traversal sequence. The third line gives its inorder traversal sequence. The numbers are separated by spaces.

### Output Format

Output a total of $n$ lines, each line containing the left and right child node numbers of the $i$-th smallest node. If the corresponding child does not exist, output $0$.

Your program should use file input and output. Read the input from a file named 'sort.in' and write the output to a file named 'sort.out'.

### Time Limit
1000ms

### Memory Limit
32768KB

This is an incorrect code to the problem:
```c++
#include <bits/stdc++.h>
using namespace std;
const int maxn = 1e3 + 7;
int n, last[maxn], mid[maxn], tree[2 * maxn];
inline void dfs(int pos, int root, int l, int r) {
    if (l == r) return;
    int ix, l1, l2, r1, r2, len1, len2, L, R, pos1, pos2;
    for (int i = l; i <= r; i++) {
        if (mid[i] == last[pos]) {
            ix = i;
            break;
        }
    }
    len1 = ix - l, len2 = r - ix;
    l2 = pos - len2, r2 = pos - 1;
    r1 = l2 - 1, l1 = r1 - len1 + 1;
    pos1 = r1, pos2 = r2;
    tree[root * 2] = last[pos1], tree[root * 2 + 1] = last[pos2];
    l1 = l, r1 = ix - 1, l2 = ix + 1, r2 = r;
    dfs(pos1, root * 2, l1, r1);
    dfs(pos2, root * 2 + 1, l2, r2);
}
int main() {
    freopen("sort.in", "r", stdin);
    freopen("sort.out", "w", stdout);
    cin >> n;
    for (int i = 1; i <= n; i++) cin >> last[i];
    for (int i = 1; i <= n; i++) cin >> mid[i];
    tree[1] = last[n];
    dfs(n, 1, 1, n);
    return 0;
}
```
### Response:
```cpp
#include <bits/stdc++.h>
using namespace std;
const int maxn = 1e3 + 7;
int n, last[maxn], mid[maxn], son[maxn][2], t[maxn];
inline void dfs(int left, int right, int l, int r) {
    int pos;
    if (left == right) return;
    for (int i = l; i <= r; i++) {
        if (mid[i] == last[right]) {
            pos = i;
            break;
        }
    }
    if (pos == l) {
        son[last[right]][1] = last[right - 1];
        dfs(left, right - 1, l + 1, r);
    } 
    else if (pos == r) {
        son[last[right]][0] = last[right - 1];
        dfs(left, right - 1, l, r - 1);
    } 
    else {
        son[last[right]][1] = last[right - 1];
        son[last[right]][0] = last[pos - l + left - 1];
        dfs(left, pos - l + left - 1, l, pos - 1);
        dfs(pos - l + left, right - 1, pos + 1, right);
    }
}
int main() {
    freopen("sort.in", "r", stdin);
    freopen("sort.out", "w", stdout);
    cin >> n;
    for (int i = 1; i <= n; i++) {
        cin >> last[i];
        t[last[i]] = 1;
    }
    for (int i = 1; i <= n; i++) cin >> mid[i];
    dfs(1, n, 1, n); 
    for (int i = 1; i < maxn; i++) {
        if (t[i] != 1) continue;
        cout << son[i][0] << " " << son[i][1] << endl;
    }
    return 0;
}
```

