long long dp[(1<<18)][18];
int main(){
	freopen("meal.in","r",stdin);
	freopen("meal.out","w",stdout);
	int n,m,k,x,y,C,cnt,now;
	long long ans;
	scanf("%d%d%d",&n,&m,&k);
	for(int i=0;i<n;i++){
		scanf("%d",&a[i]);
	}
	for(int i=0;i<k;i++){
		scanf("%d%d%d",&x,&y,&C);
		x--;
		y--;
		c[x][y]=C;
	}
	for(int i=0;i<n;i++){
		dp[(1<<i)][i]=a[i];
	}
	for(int i=1;i<(1<<n)-1;i++){
		for(int j=0;j<n;j++){
			if(!((i>>j)&1)){
				for(int k=0;k<n;k++){
					if((i>>k)&1){
						dp[i|(1<<j)][j]=max(dp[i|(1<<j)][j],dp[i][k]+c[k][j]+a[j]);
					}
				}
			}
		}
	}
	ans=0;
	for(int i=0;i<(1<<n);i++){
		cnt=0;
		now=i;
		while(now){
			if(now&1){
				cnt++;
			}
			now>>=1;
		}
		if(cnt==m){
			for(int j=0;j<n;j++){
				ans=max(ans,dp[i][j]);
			}
		}
	}
	printf("%lld\n",ans);
	return 0; 
}
