bool check(int c,int i,int f) {
    if (f==2) {
        return !row1[i] && !x1[c+i] && !y1[c-i+n] && vis[c][i]==1;
    } else {
        return !row2[i] && !x2[c+i] && !y2[c-i+n] && vis[c][i]==1;
    }
}
void dfs(int c) {
    if (c==n) {
        ans++;
        return;
    }
    for (int i=0;i<n;i++) {
        if (check(c,i,2)) {
            vis[c][i]=2;
            row1[i]=x1[c+i]=y1[c-i+n]=true;
            for (int j=0;j<n;j++) {
                if (check(c,j,3)) {
                    vis[c][j]=3;
