    for(int i=1;i<=n;i++){
        if(check(c,i,color)&&a[i][c]!=0){
            row[color][i]=x1[color][c+i]=x2[color][c-i+n]=true;
            a[i][c]=0;
            dfs(c+1,color);
            a[i][c]=1;
            row[color][i]=x1[color][c+i]=x2[color][c-i+n]=false;
        }
    }
}
