We have $N$ positive integers, all less than $10000$. Now we need to sort these positive integers in ascending order based on the sum of the digits of each positive integer, i.e., the smaller the sum of the digits, the higher the ranking. If the sums are equal, sort the positive integers in ascending order.

### Input Format

The input has $2$ lines

  * The first line is an integer $N$, $0 < N < 101$;
  * The second line contains $N$ positive integers separated by spaces, all less than $10000$.

### Output Format

There is $1$ line in the output, which contains the $N$ positive integers sorted according to the requirements of the question, separated by spaces.

### Time Limit
1000ms

### Memory Limit
32768KB

This is an incorrect code to the problem:
```c++
#include <iostream>
#include <algorithm>
#include <iomanip>
#include <cmath>
int A[10000];
using namespace std;
bool cmp(int a, int b) {
    int m1 , m2;
    m1 = a % 10 + a / 10;
    m2 = b % 10 + b / 10;
    if (m1 != m2){
        return m1 < m2;
    }
 return a < b;
}

int main() {
   int n;
   cin >> n;
   for (int i=0; i < n;i++){
       cin >> A[i];
   }
   sort (A ,A+n,cmp);
    for (int i=0; i < n;i++){
       cout << A[i] << " ";
   }
}
```
### Response:
```cpp
#include <iostream>
#include <algorithm>
#include <iomanip>
#include <cmath>
int A[10000];
using namespace std;
int cmp(int a, int b) {
    int m1 = a;
    int s1 = 0;
    while (m1 != 0){
        s1 += m1 % 10;
        m1 /= 10;
    }
    int m2 = b;
    int s2 = 0;
    while (m2 != 0){
        s2 += m2 % 10;
        m2 /= 10;
    }
    if (s1 != s2){
        return s1 < s2;
    }
 return a < b;
}

int main() {
   int n;
   cin >> n;
   for (int i=0; i < n;i++){
       cin >> A[i];
   }
   sort (A ,A+n,cmp);
    for (int i=0; i < n;i++){
       cout << A[i] << " ";
   }
}
```

