#include<iostream>
#include<string>
using namespace std;
int main(){
    string a;
    cin>>a;
    while(a.find("sss")!=string::npos){
            a.replace(a.find("sss"),3,".");
    }
    while(a.find("kkk")!=string::npos){
            a.replace(a.find("kkk"),3," ");
    }
    for(int i=0;i<a.size();i++){
        if(a[i]>='a'&&a[i]<='c'){
            a[i]='7'+a[i]-'a';
        }else if(a[i]>='d'&&a[i]<='z'||a[i]>='3'&&a[i]<='9'){
            a[i]-=3;
        }else if(a[i]>='0'&&a[i]<='2'){
            a[i]='x'+a[i]-'0';
        }
    }
    cout<<a;
}
