    if (depth == 0) {
        if (sum > b) ans = min(sum - b, ans);
        return;
    }
    if (sum - b >= ans) return;
    for (int i = last + 1; i <= n - depth; i++) {
        dfs(depth - 1, sum + h[i], i);
    }
    return;
}
int main() {
    freopen("shelf.in", "r", stdin);
    freopen("shelf.out", "w", stdout);
