    int a, b;
    cin >> a >> b;
    int a0, b0; 
    if (a < 0) {

        a0 = -a;
    } else {
        a0 = a;
    }
    if (b < 0) {

        b0 = -b;
    } else {
        b0 = b;
    }

    if (a0 == b0) {
        cout << b << " " << a << endl;

    } else if (a0 > b0 ) {
        cout << b << " " << a << endl;
