#include <iostream>
#include <string>
#include <stack>
using namespace std;
int cal(int x, int y, char o) {
    if (o == '+')
        return x + y;
    if (o == '-')
        return y - x;
    if (o == '*')
        return x * y;
    if (o == '/')
        return y / x;
}
int main(){
    string s;
    cin >> s;
    int n = s.size();
    stack<char> op;
    stack<int> num;
    for (int i = 0; i < n; i++) {
        if (s[i] >= '0' && s[i] <= '9') {
            int tmp = s[i] - '0';
            num.push(tmp);
        } else if (s[i]=='('){
            op.push(s[i]);
