            while(op.top()!='('){
                int tmp1 = num.top();
                num.pop();
                int tmp2 = num.top();
                num.pop();
                num.push(cal(tmp1, tmp2, op.top()));
                op.pop();
        }
            op.pop();
        }
        else if (s[i] == '+' || s[i] == '-') {
            while (!op.empty()&&op.top()!='(') {
                int tmp1 = num.top();
                num.pop();
                int tmp2 = num.top();
                num.pop();
                num.push(cal(tmp1,tmp2,op.top()));
                op.pop();
            }
            op.push(s[i]);
        } else {
            while (!op.empty() && (op.top() == '*' || op.top() == '/')) {
                int tmp1 = num.top();
                num.pop();
                int tmp2 = num.top();
                num.pop();
                num.push(cal(tmp1, tmp2, op.top()));
                op.pop();
