        ans++;
        return;
    }
    for (int i = 0; i < n; i++) {
        if (a[b.size()][i] == 0) continue;
        b.push_back(i);
        for (int j = 0; j < n; j++) {
            if (j == i) continue;
            if (a[w.size()][j] == 0) continue;
