#include <bits/stdc++.h>
using namespace std;
int n, ans;
vector<vector<int> > a;
void dfs(vector<int> b, vector<int> w, vector<vector<int> > m) {
    if (w.size() == n) {
        ans++;
        return;
    }
    if (b.size() >= n) {
        for (int i = 0; i < n; i++) {
            if (m[w.size()][i] == 0) continue;
            if (find(w.begin(), w.end(), i) != w.end()) {
                continue;
            }
            bool flag = false;
            for (int j = 0; j < w.size(); j++) {
                if (abs(j - (int)w.size()) == abs(w[j] - i)) {
                    flag = true;
                    break;
                }
            }
            if (flag) continue;
            m[w.size()][i] = 0;
            w.push_back(i);
            dfs(b, w, m);
            w.pop_back();
            m[w.size()][i] = 1;
        } 
        return;
    }
    for (int i = 0; i < n; i++) {
        if (m[b.size()][i] == 0) continue;
        if (find(b.begin(), b.end(), i) != b.end()) {
            continue;
        }
        bool flag = false;
        for (int j = 0; j < b.size(); j++) {
            if (abs(j - (int)b.size()) == abs(b[j] - i)) {
                flag = true;
                break;
            }
        }
        if (flag) continue;
        m[b.size()][i] = 0;
        b.push_back(i);
        dfs(b, w, m);
        b.pop_back();
        m[b.size()][i] = 1;
    } 
}
int main() {
    freopen("queen.in", "r", stdin);
    freopen("queen.out", "w", stdout);
    cin >> n;
    vector<int> t;
    for (int i = 0; i < n; i++) {
        a.push_back(t);
        for (int j = 0; j < n; j++) {
            int tmp;
            cin >> tmp;
            a[i].push_back(tmp);
        }
    }
    vector<int> b, w;
    dfs(b, w, a);
    cout << ans << endl;
    return 0;
}
```

