```cpp
#include <bits/stdc++.h>
using namespace std;
int n;
int a[1000], b[1000], c[1000];
int Right[1000], Left[1000];
void dfs(int l1, int r1, int l2, int r2) {
    int pos;
    if (l1 == r1) {
        return;
    }
    for (int i = l2; i <= r2; i++) {
        if (b[i] == a[r1]) {
            pos = i;
            break;
        }
    }
    if (pos == l2) {
        Right[a[r1]] = a[r1 - 1];
        dfs(l1, r1 - 1, l2 + 1, r2);
    } else if (pos == r2) {
        Left[a[r1]] = a[r1 - 1];
        dfs(l1, r1 - 1, l2, r2 - 1);
    } else {
        Left[a[r1]] = a[pos - l2 + l1 - 1];
        Right[a[r1]] = a[r1 - 1];
        dfs(l1, pos - l2 + l1 - 1, l2, pos - 1);
        dfs(pos - l2 + l1, r1 - 1, pos + 1, r2);
    }
}
int main() {
    freopen("sort.in", "r", stdin);
    freopen("sort.out", "w", stdout);
