    return !row[i] && !x1[i+c] && !x2[i-c+n] && vis[i][c]==false;
}
void dfs(int c,int time){
    if(c==n){
        if(time==1){
            dfs(0,2);
        }
        if(time==2){
            ans++;
        }
        return;
    }
    for(int i=0; i<n; i++){
        if(check(i,c)){
            row[i]=x1[i+c]=x2[i-c+n]=true;
            vis[i][c]=true;
            dfs(c+1,time);
            vis[i][c]=false;
            row[i]=x1[i+c]=x2[i-c+n]=false;
        }
    }
}
