        while (j < m) {
            if (h[j] <= cs[i].height) {
                j++;
            } else {
                cs[i].cnt = j - temp;
                temp = j;
                break;
            }
        }
        if (j == m) {
            cs[i].cnt = j - temp;
            temp = j;
        }
    }
    sort(cs, cs + n, cmp2);
    for (int i = 0; i < n; i++) {
