#include<bits/stdc++.h>
using namespace std;
void fly(long long n){
    if(n==12){
        printf(", 6, 3, 12\n");
        return ;
    }
    if(n==6){
        printf(", 3, 12, 6\n");
        return ;
    }
    if(n==3){
        printf(", 12, 6, 3\n");
        return ;
    }
    if(n%2==0){
        printf(", %lld",n/2);
        fly(n/2);
    }else{
        printf(", %lld",6*((n-1)/2)+6);
        fly(6*((n-1)/2)+6);
    }
