    freopen("queen.in","r",stdin);
    freopen("queen.out","w",stdout);
    cin>>n;
    for(int i=0;i<n;++i)
    {
        for(int j=0;j<n;++j)
        {
            cin>>chess[i][j];
        }
    }
    dfs(0);
    cout << ans*(ans-1) << endl;
    return 0;
}
