### Response:
```cpp
#include <bits/stdc++.h>
using namespace std;
int ans = 0;
int n;
bool row[10], x1[20], x2[20],rowb[10], x1b[20], x2b[20];
int chess[10][10];
void _set()
{
    memset(row,false,sizeof row);
    memset(x1,false,sizeof x1);
    memset(x2,false,sizeof x2);
}
bool check(int c, int i) {
    return !row[i] && !x1[c + i] && !x2[c - i + n]&&chess[i][c]==1;
}
bool checkb(int c, int i) {
    return !rowb[i] && !x1b[c + i] && !x2b[c - i + n]&&chess[i][c]==1;
}
void dfs(int c,int cb,bool cmp) {
    if(cb==n&&cmp)
    {
        ++ans;
        return;
    }
    if (c == n&&!cmp) {
        dfs(c,cb,true);
        return;
    }
    if(!cmp)
    {
        for (int i = 0; i < n; i++) {
            if (check(c, i)) {
                chess[i][c]=0;
                row[i] = x1[c + i] = x2[c - i + n] = true;
                dfs(c + 1,cb,false);
                chess[i][c]=1;
                row[i] = x1[c + i] = x2[c - i + n] = false;
            }
        }
    }else
    {
         for (int i = 0; i < n; i++) {
            if (checkb(cb, i)) {
                rowb[i] = x1b[cb + i] = x2b[cb - i + n] = true;
                dfs(c,cb + 1,true);
                rowb[i] = x1b[cb + i] = x2b[cb - i + n] = false;
            }
        }
    }

}
int main() {
    freopen("queen.in","r",stdin);
    freopen("queen.out","w",stdout);
    cin>>n;
    for(int i=0;i<n;++i)
    {
        for(int j=0;j<n;++j)
        {
            cin>>chess[i][j];
        }
    }
    dfs(0,0,false);
    cout << ans << endl;
    return 0;
}
```

