    {
        cin >> q[i];
    }
    for (int i = 1; i <= M; i++)
    {
        cin >> w[i];
    }
    for (int i = 1; i <= N; i++)
    {
        for (int j = X; j >= p[i]; j--)
        {
            dp[j] = max(dp[j], dp[j - p[i]] + v[i]);
        }
    }
    for (int i = 1; i <= M; i++)
    {
        for (int j = X; j >= q[i]; j--)
        {
            if (dp[j - q[i]] != 0)
            {
                dp[j] = max(dp[j], dp[j - q[i]] + w[i]);
            }
        }
    }
