#include <iostream>
#include <cstdio>
#include <algorithm>
using namespace std;
int Middle[35]={0},End[35]={0},n=0,Left[35]={0},Right[35]={0},root=0,num[35]={0};
void dfs(int l1,int r1,int l2,int r2)
{
    if(l1==r1)
    {
        return;
    }
    int g;
    for(int i=l2;i<=r2;i++)
    {
        if(End[i]==Middle[r1])
        {
            g=i;
            break;
        }
