        Left[Middle[r1]]=Middle[r1-1];
        dfs(l1,r1-1,l2,r2-1);
    } else {
        Left[Middle[r1]]=Middle[g-l2+l1-1];
        Right[Middle[r1]]=Middle[r1-1];
        dfs(l1,g-l2+l1-1,l2,g-1);
        dfs(g-l2+l1,r1-1,g+1,r2);
    }
    return;
}
