        cin >> g.r >> g.p >> k;
        for (int i = 0; i < k; i++) {
            g.t = t++;
            sumr[g.r] += g.p;
            num[g.r] += 1.0;
            gems.push_back(g);
        }
    }
    sort(gems.begin(), gems.end(), comp);
    long long sum = 0;
    for (int i = 0; i < gems.size(); i++) {
        sum += abs(gems[i].t - i);
    }
    cout << sum << endl;
    return 0;
}
