    ans += x % 10;
    x /= 10;
}

    return ans;
}
bool cmp (int x, int y) {
    if (sum(x) != sum(y)) {
        return sum(x) < sum(y);
    }
    if (x % 2 != y % 2) {
        return x % 2 > y % 2;    
    }
    return x > y;

}
int main() {
    int n;
    cin >> n;
    for (int i = 0; i < n; i++) {
        cin >> a[i];
