        switch(m){
            case '6':{
                break;
            }case '7':{
                n-=5;
                break;
            }case '12':{
                n-=20;
                break;
            }case '15':{
                if(n>=0){
                    cout<<"Yes";
                }else if(n<0){
                    cout<<"No";
                }break;
