    }
    while(a.find("can you")!=string::npos){
        a.replace(a.find("can you"),a.find("can you")+7,"I can");
    }
    while(a.find("could you")!=string::npos){
       a.replace(a.find("could you"),a.find("could you")+9,"I could");
