{
    int n, ans = 1;
    cin >> n;
    for (int i = 1; i <= n; i++)
    {
        cin >> num[i].l >> num[i].b;
        if (num[i].l > num[i].b)
        {
            num[i].isswap = 1;
            swap(num[i].l, num[i].b);
        }
        if (num[i].b - num[i].l > num[ans].b - num[ans].l || (num[i].b - num[i].l == num[ans].b - num[ans].l && num[i].l < num[ans].l))    ans = i;
    }
    if (num[ans].isswap)    cout << num[ans].b << " " << num[ans].l;
    else     cout << num[ans].l << " " << num[ans].b;
}
```

