{
   int a=0;
   for(int i=0;i<8;i++)
   {
       char c;
       if(scanf("%c",&c)==EOF){
           printf("Error");
           exit(0);
       }

   } 
}
```
### Response:
```cpp
#include<cstdio>
#include<cstring>
#define W {printf("Error");return 0;}
char a[200010],tar[200010]="",tmp[10];
int main()
{
	freopen("information.in","r",stdin);
	freopen("information.out","w",stdout);
	scanf("%s",a);
	if(strlen(a)%8) {W;}
	int i=0,lentar=0;
	while(true){
		int num=0;
		for(int j=0;j<8;j++,i++){
			if(a[i]=='\0'){
				printf("%s",tar);
				return 0;
			}
			else if(a[i]!='1'&&a[i]!='0'){
				W;
			}
			num=(num<<1)|(a[i]-'0');
		}
		switch(num>>5)
		{
			case 7:sprintf(tar+lentar,"%c",' ');lentar++;break;
			case 6:
			case 4:W;break;
			case 5:
			{
				int m=num&31;
				if(m>25) {W;}
				else{
					sprintf(tar+lentar,"%c",'A'+m);
					lentar++;
				}
				break;
			}
			default:
			{
				int numb=0;
				for(int j=0;j<8;j++,i++){
					if(a[i]=='\0'){
						W;
					}
					else if(a[i]!='1'&&a[i]!='0'){
						W;
					}
					numb=(numb<<1)|(a[i]-'0');
				}
				if(numb>>7) {
					W;
				}
				sprintf(tmp,"%d",num/2+numb/2);
				sprintf(tar+lentar,"%s",tmp);
				lentar+=strlen(tmp);
			}
		}
	}
	fclose(stdin);
	fclose(stdout);
	return 0;
}
```

