#include <bits/stdc++.h>
using namespace std;
int dp[1005][5010];
int w[5010], c[5010], x[5010], y[5010];
int main()
{
    freopen("health.in", "r", stdin);
    freopen("health.out", "w", stdout);
    int n, m, X;
    cin >> n >> m >> X;
    for (int i = 1; i <= n; i++){
        cin >> w[i]; 
    }
    for (int i = 1; i <= n; i++){
        cin >> c[i]; 
    }
    for (int i = 1; i <= m; i++){
        cin >> x[i]; 
    }
    for (int i = 1; i <= m; i++){
        cin >> y[i]; 
    }
    for (int i = 1; i <= n; i++){
        for (int j = 0; j <= X; j++){
            if (j >= w[i]){
                dp[i][j] = max(dp[i - 1][j - w[i]] + c[i], dp[i - 1][j]);
            }
            else{
                dp[i][j] = dp[i - 1][j];
            }
        }
    }
    for (int i = n + 1; i <= n + m; i++){
        for (int j = 0; j <= X; j++){
            if (j >= x[i - n]  && dp[i - 1][j - x[i - n]]){
                dp[i][j] = max(dp[i - 1][j - x[i - n]] + y[i - n], dp[i-1][j]);
            }
            else{
                dp[i][j] = dp[i - 1][j];
            }
        }
    }
    cout << dp[n + m][X];
    return 0;
}
