                    dp[i | (1 << j)][j] = max(dp[i | (1 << j)][j], dp[i][k] + a[j] + c[k][j]);
                }
            }
        }
    }
    int ans = 0, cnt, now;
    for (int i = 0; i < (1 << n); i++) {
        cnt = 0;
        now = i;
        while(now) {
            if(now & 1) {
                cnt++;
            }
            now >>= 1;
        }
        if(cnt == m) {
            for (int j = 0; j < n; j++) {
                ans = max(ans, dp[i][j]);
            }
        }
    }
