            if(isupper(s[j])&&s[j]!='I') s[j]+="a"-"A";
            if(s[j]=='?') s[j]='!';
            if(s[j]!=' ') f[x]+=s[j];
            if(s[j+1]==s.size()||s[j+1]==' ') x++;
        }
        for(int j=0;j<=x;j++){
            if((f[j]=="can"||f[j]=="could")&&f[j+1]=="you"){
                cout<<"I "<<f[j]<<" ";
                j++;
            }
            else if(f[j]=="I"||f[j]=="me") cout<<"you ";
            else cout<<f[j]<<" ";
        }
        cout<<endl;
    }
    return 0;
}
