#include <bits/stdc++.h>
using namespace std;
int last=-1,r=0;
string ans;
bool ans_f=1,flag=0;
string sss(string s){
    string temp="";
    for(int i=3;i<s.size();i++){
        temp+=s[i];
    }
    return temp;
}void fun(string s){
    if((s[0]=='1')&&(s[1]=='0')&&(s[2]=='1')){
        string temp=sss(s);
        int t=stoi(temp,0,2);
        if(t>26) ans_f=0;
        else ans+=(t+'A');
    }else if((s[0]=='1')&&(s[1]=='1')&&(s[2]=='1')) ans+=" ";
    else if((s[0]=='0')){
        string temp=s;
        int t=stoi(temp,0,2);
        t/=2;
        if(r==0){
            flag=1;
            last=t;
        }else if(r==1){
            r=0;
            flag=0;
            ans+=to_string(last+t);
            last=-1;
        }else{
            ans_f=0;
        }
    }else ans_f=0;
    if(flag) r++;
    if(r>=2) ans_f=0;
}int main() {
    freopen("information.in", "r", stdin);
    freopen("information.out", "w", stdout);
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    cout.tie(nullptr);
    string s;
    cin>>s;
    if(s.size()%8!=0){
        cout<<"Error";
        return 0;
    }
    for(int i=0;i<s.size();i+=8){
        string temp="";
        for(int j=i;j<i+8;j++){
            temp+=s[j];
        }
        fun(temp);
        if(temp[0]=='0'){
            if(i==s.size()-8) ans_f=0;
            else if(s[i+8]!='0') ans_f=0;
            else{
                temp="";
                i+=8;
                 for(int j=i;j<i+8;j++){
                    temp+=s[j];
                }
                fun(temp);
            }
        }
        if(!ans_f){
            cout<<"Error";
            return 0;
        }
    }
    cout<<ans;
    return 0;
}
