#include <iostream>
#include <algorithm>
using namespace std;
bool cmp1(int x,int y){
    int h = x,sum1 = 0,sum2 = 0;
    while (h > 0){
        sum1 += h % 10;
        h /= 10;
    }
    h = y;
    while (h > 0){
        sum2 += h % 10;
        h /= 10;
    }
    if (sum1 == sum2){
        return x >= y;
