    freopen("elevator.out", "w", stdout);
    int n;
    cin >> n;
    long long floor_now = 0;
    long long ans = 0;
    for(int i = 1; i <= n; i++){
        cin >> a[i];
    }
    sort(a, a + n);
    for(int i = 1; i <= n; i++){
