            ans += (a[i] - floor_now) * 5;
        }
        if(floor_now == a[i]){
            ans += 2;
        }else{
            ans += 5;
        }
        floor_now = a[i];
    }
    floor_now = a[n];
    ans += floor_now * 4;
    cout << ans << endl;
    return 0;
}
```
