    int n;
    cin >> n;
    int x,y,b = 0,c = 0,a = 0;
    for(int i = 0;i < n;i++){
        cin >> x >> y;
        if(abs (x - y) > b){
            b = x - y;
            c = x;
            a = y;
        }
    }
    cout << c << " " << a;
