#include <iostream>
#include<cmath>
using namespace std;
int main() {
    int n;
    cin >> n;
    int x,y,b = 0,c = 0,a = 0;
    for(int i = 1;i <= n;i++){
        cin >> x >> y;

        if(abs (x - y) > b){
            b = abs(x - y);
            c = x; 
            a = y; 

        }else if(abs(x - y) == b){
            if(min(x , y) < min(a , c)){
                b = abs(x - y);
                c = x; 
                a = y; 
            }
        }
    }
    cout << c << " " << a;
    return 0;
}
