	for (int i = 1; i <= n; i++) {
		cin >> postOrder[i];
	}
	for (int i = 1; i <= n; i++) {
		cin >> inOrder[i];
	}
	dfs(1, n, 1, n);
	sort(inOrder + 1, inOrder + n + 1);
	for (int i = 1; i <= n; i++) {
		cout << lc[inOrder[i]] << " " << rc[inOrder[i]] << endl;
	}
	return 0;
}
