### Time Limit
1000ms

### Memory Limit
131072KB

This is an incorrect code to the problem:
```c++
#include<bits/stdc++.h>
using namespace std;
int ans = INT_MAX,n,shelf,hight[30];
void dfs(int k,int sum){
    if(k > n){
        if(sum < ans){
            ans = sum;
        }
        return;
    }
    if(sum >= ans) return;
    dfs(k+1,sum + hight[k]);
    dfs(k+1,sum);
}
