    freopen("shelf.in","r",stdin);
    freopen("shelf.out","w",stdout);
    scanf("%d%d",&n,&shelf);
    for(int i = 1;i <= n;i++){
        scanf("%d",&(hight[i]));
    }
    dfs(1,0);
    printf("%d",ans-shelf);
    fclose(stdin);
    fclose(stdout);
    return 0;
}
```

