```cpp
#include <bits/stdc++.h>
using namespace std;
const int maxn = 35;
const int maxnode = 1005;
int N, medi[maxn], suff[maxn];
int lc[maxnode], rc[maxnode];
int pos_in_medi[maxnode];
int solve(int l1, int r1, int *me, int l2, int r2, int *su) {

    if (l1 > r1) return 0;
    int rt = su[r2];
    int p = pos_in_medi[rt];
    int len_l = p - l1, len_r = r1 - p;
    lc[rt] = solve(l1, p - 1, me, l2, l2 + len_l - 1, su);
    rc[rt] = solve(p + 1, r1, me, r2 - len_r, r2 - 1, su);
    return rt;
}
int main() {
    freopen("sort.in", "r", stdin);
    freopen("sort.out", "w", stdout);
    scanf("%d", &N);
    for (int i = 1; i <= N; i++) scanf("%d", &suff[i]);
    for (int i = 1; i <= N; i++) scanf("%d", &medi[i]);
    for (int i = 1; i <= N; i++)
    pos_in_medi[medi[i]] = i;
    solve(1, N, medi, 1, N, suff);
    for (int i = 1; i <= 1000; i++)
        if (pos_in_medi[i]) printf("%d %d\n", lc[i], rc[i]);
    return 0;
}
```

