	for(int i=1; i<=n; i++){
		for(int j=1; j<=m; j++){
			if(a[i][j]>0&&!vis[i][j]){
				s = 0;
				bfs(i,j);
				if(s>ans){
					ans = s;
				}
			}
		}
	}
	cout << ans;
	return 0;
}
