#include <bits/stdc++.h>
using namespace std;
int dis[105][105];
pair<int, int> pre[105][105];
int dx[4] = {0, 0, -1, 1};
int dy[4] = {-1, 1, 0, 0};
int n, m, k, x11, y11, x22, y22;
string ch[105];
void bfs(int sx, int sy) {
    deque<pair<int, int> > que;
    que.push_front({sx, sy});
    dis[sx][sy] = 0;
    while (que.size()) {
        auto tp = que.front();
        que.pop_front();
        int x = tp.first, y = tp.second;
        if (dis[x][y] > k)  continue;
        if (x == x22 && y == y22)   return;
        for (int i = 0; i < 4; ++i) {
            int tx = x + dx[i];
            int ty = y + dy[i];
            if (tx > 0 && tx <= n && ty > 0 && ty <= m && ch[tx][ty - 1] == '.') {
                int flag = 1;
                if ((x == sx && y == sy) || pre[x][y].first == tx || pre[x][y].second == ty) { 
                    flag = 0;
                }
                if (dis[tx][ty] > dis[x][y] + flag) {
                    pre[tx][ty] = {x, y};
                    dis[tx][ty] = dis[x][y];
                    if (flag == 0) { 
                        que.push_front({tx, ty});
                    } else {
                        ++dis[tx][ty];
                        que.push_back({tx, ty});
                    }
                }
            }
        }
    }
}
void init() {
    memset(pre, 0, sizeof (pre));
    memset(dis, 0x3f, sizeof (dis));
    n = m = k = x11 = y11 = x22 = y22 = 0;
}
int main() {
    freopen("maze.in", "r", stdin);
    freopen("maze.out","w",stdout);
    int T;
    cin >> T;
    while (T--) {
        init();
        cin >> n >> m;
        for (int i = 1; i <= n; ++i) {
            cin >> ch[i];
        }
        cin >> k >> y11 >> x11 >> y22 >> x22;
        bfs(x11, y11);
        if (dis[x22][y22] <= k) {
            cout << "yes\n";
        } else {
            cout << "no\n";
        }
    }
}
```

