	node[res].l = dfs(l-1,b,c);

	node[res].r = dfs(len-l,b+l,c+l-1);
	return res;
} 
void bfs() {
	queue<int> q;
	q.push(1);
	while(q.size()) {
		int cur = q.front();q.pop();
		if(cur != 1) printf(" ");
		printf("%d",node[cur].val);
		if(node[cur].l != -1) q.push(node[cur].l);
		if(node[cur].r != -1) q.push(node[cur].r);
	}
    printf("\n");
}
