string solve(string s) {
    if (s.size() % 8 != 0) return "Error";
    for (int i = 0; i < s.size(); i++) {
        char ch = s[i];
        if (ch != '0' && ch != '1') {
            return "Error";
        }
    }    
    string ret = "";
    for (int i = 0; i < s.size(); i += 8) {
        if (s.substr(i, 3) == "101") {
            int t = stoi(s.substr(i + 3, 5), 0, 2);
            if (t > 25) return "Error";
            ret += 'A' + t;
            continue;
        }
        if (s.substr(i, 3) == "111") {
            ret += ' ';
            continue;
        }
        if (s[i] == '0') {
            if (i + 8 >= s.size() || s[i + 8] != '0') return "Error";
                int t = stoi(s.substr(i, 8), 0, 2) / 2;
                i += 8;
                t += stoi(s.substr(i, 8), 0, 2) / 2;
                ret += to_string(t);
                continue;
        }
            return "Error";
    }
        return ret;
}
