    int cnt = 0;
    while (sum > 0) {
        cnt += sum % 10;
        sum /= 10;
    }
    return cnt;
}
bool cmp(int x, int y) {
    if (sum(x) != sum(y)) {
        return sum(x) < sum(y);
    } else {
        return x < y;
    }
