    freopen("stone.in","r",stdin);
    freopen("stone.out","w",stdout);
    cin >> n;
    for(int i=0;i<n;i++){
        cin >> fennv[i] >> kuangbao[i];
    }
    dfs(0,0,0,0);
    cout << ans;
    return 0;
}
```
