    if (u == n) {
        if (cnt && (ans == -1 || abs(sum - mul) < ans)) {
            ans = abs(sum - mul);
        }
        return;
    }
    dfs(u + 1, cnt + 1, sum + b[u], mul * a[u]);
    dfs(u + 1, cnt, sum, mul);
}
int main() {
