    freopen("pair.in", "r", stdin);
    freopen("pair.out", "w", stdout);
    int n;
    cin >> n;
    int ans = 0; 
    for(int i = 1; i <= n; i++){
        int x;
        cin >> x;
        if(x)
            s[i] = s[i - 1] + 1;
        else
            s[i] = s[i - 1] - 1;
        if(!s[i])
            ans = max(ans, i);
    }
    map<int, int>m;
    for(int i = 1; i < n; i++){
        if(!m.count(s[i]))
            m[s[i]] = i;
        else
            ans = max(ans, i - m[s[i]]);
    }
    cout << ans << endl;
    return 0;
}
