###Instruction:
Problem Description:
# 2n Queens Problem
Given an $n*n$ chessboard, some positions on the board cannot place queens. Now you need to place $n$ black queens and $n$ white queens on the board so that any two black queens are not in the same row, same column, or same diagonal (including positive and negative diagonals), and any two white queens are not in the same row, same column, or same diagonal (including positive and negative diagonals). How many placement methods are there in total? $n$ is less than or equal to $8$.

### Input Format

The first line of the input is an integer $n$, indicating the size of the chessboard.

The following $n$ lines, each line contains $n$ integers $0$ or $1$. If an integer is $1$, it means that the corresponding position can place a queen, and if an integer is $0$, it means that the corresponding position cannot place a queen.

### Output Format

Output an integer, indicating the total number of placement methods.

Your program should use file input and output. Read the input from a file named 'queen.in' and write the output to a file named 'queen.out'.

### Time Limit
1000ms

### Memory Limit
65536KB

This is an incorrect code to the problem:
```c++
#include <bits/stdc++.h>
using namespace std;
int ans = 0, n, a[10][10];
bool row[10], x1[20], x2[20];
bool check(int i, int c) {
    return !row[i] && !x1[i + c] && !x2[i - c + n];
}
void dfs(int c) {
    if (c == n) {
        ans++;
        return;
    }
    for (int i = 0; i < n; i++) {
        if (check(i, c) && a[c][i]) {
            row[i] = x1[i + c] = x2[i - c + n] = true;
            dfs(c + 1);
            row[i] = x1[i + c] = x2[i - c + n] = false;
        }
    }
}
int main() {
    freopen("queen.in", "r", stdin);
    freopen("queen.out", "w", stdout);
    cin >> n;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            cin >> a[i][j];
        }
    }
    dfs(0);
    cout << ans << endl;
    return 0;    
}
```
### Response:
```cpp
#include<cmath>
#include<iostream>
using namespace std;
const int maxn = 10; 
int n;
int map_Q[maxn][maxn];
int posb[maxn]={0};
int posw[maxn]={0};
int ans;
bool checkw(int cur){
    for( int i = 1; i < cur; i++)
        if( posw[i] == posw[cur] || abs(i-cur) == abs(posw[i]-posw[cur]))
            return false;
    return true;
}   

bool checkb(int cur){  
    for( int i = 1; i < cur; i++)  
        if( posb[i] == posb[cur] || abs(i-cur) == abs(posb[i]-posb[cur]))  
            return false;  
    return true;  
}  

void dfs_white( int cur){  
    if( cur == n+1){  
        ans++;  
      }
    for( int i = 1; i <= n; i++){
        if( posb[cur] == i)
            continue;
        if( map_Q[cur][i] == 0)
            continue;
        posw[cur] = i;
        if( checkw(cur))
            dfs_white(cur+1);
    }  
}  
void dfs_black( int cur)  {
    if( cur == n+1){  
        dfs_white(1);  
    }  
    for( int i = 1; i <= n; i++){
        if( map_Q[cur][i] == 0)
            continue;
        posb[cur] = i;
        if( checkb(cur))
            dfs_black(cur+1);
    }
}
int main(){
    freopen("queen.in","r",stdin);
    freopen("queen.out","w",stdout);
    cin>>n;
    for( int i = 1; i <= n; i++)
        for( int j = 1; j <= n; j++)  
            cin>>map_Q[i][j];
    ans = 0;
    dfs_black(1);
    cout<<ans<<endl; 

    return 0;  
}
```

