long long du[1001];
long long dad[1001], son[1001][1001];
void insert(int x, int y) {
    node tmp;
    tmp.y = y;
    s[x].push_back(tmp);
    du[x]++;
}
int main(){
    freopen("p.in","r",stdin);
    freopen("p.out","w",stdout);
    int t;
    cin >> t;
    for(int i = 0; i < t; i++){
        int n;
        cin >> n;
        for(int j = 0; j <= n; j++){
            s[j].clear();
            du[j] = 0;
            dad[j] = 0;
            for(int k = 0; k <= n; k++){
                son[j][k] = 0;
            }
        }
        for(int j = 1; j <= n - 1; j++){
            int x, y;
            cin >> x >> y;
            dad[y] = x;
            son[x][j] = y;
            insert(x, y);
        }
        int pd = 0;
        int ans = 0;
        for(int j = 1; j <= n; j++){
            for(int k = 1; k < n; k++){
                if(du[j] >= du[dad[j]] && du[j] >= du[son[j][k]]){
                    pd = 1;
                }else {
                    pd = 0;
                    break;
                }
            }
            if(pd == 1){
                ans++;
            }
        }
        cout << ans << endl;
    }
    return 0;
}
```

