int sum(int x) {
    int ans = 0;
    while (x) {
        ans += x % 10;
        x /= 10;
    }
    return ans;
}
bool cmp (int a, int b) {
    if (sum (a) != sum (b)) {
        return sum(a) < sum(b);
    }
    return a < b;
}
