#include <iostream>
#include <cmath>
using namespace std;
int main() {
    int n;
    cin >> n;
    int p, q;
    for (int i = 0; i < n; i++) {
        int x, y;
        cin >> x >> y;
        int temp = abs(x - y);
        int max = abs(p - q);
        if (temp > max) {
            p = x;
            q = y;
        } else if (temp == max) {
            if (min(p, q) > min(x, y)) {
                p = x;
                q = y;
            }
        }
    }
    cout << p << " " << q << endl;
    return 0;
}
```

